package com.example.samlsp;

import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.security.config.Customizer;
import org.springframework.security.config.annotation.web.builders.HttpSecurity;
import org.springframework.security.config.annotation.web.configuration.EnableWebSecurity;
import org.springframework.security.web.SecurityFilterChain;
import org.springframework.security.web.authentication.logout.HttpStatusReturningLogoutSuccessHandler;

@Configuration
@EnableWebSecurity
public class SecurityConfig {

    @Bean
    SecurityFilterChain securityFilterChain(HttpSecurity http) throws Exception {
        http
            .authorizeHttpRequests(authorize -> authorize
                .requestMatchers("/", "/error", "/logout-success").permitAll() // Allow public access to home, error, and logout success pages
                .anyRequest().authenticated() // All other requests require authentication
            )
            .saml2Login(Customizer.withDefaults()) // Enable SAML2 login with default settings
            .saml2Logout(logout -> logout
                .logoutSuccessHandler(new HttpStatusReturningLogoutSuccessHandler()) // Handle successful logout for SAML
                .logoutSuccessUrl("/logout-success") // Redirect to this URL after successful logout
            );
        return http.build();
    }
}
package com.example.samlsp;

import org.springframework.security.core.annotation.AuthenticationPrincipal;
import org.springframework.security.saml2.provider.service.authentication.Saml2AuthenticatedPrincipal;
import org.springframework.stereotype.Controller;
import org.springframework.ui.Model;
import org.springframework.web.bind.annotation.GetMapping;

@Controller
public class HelloController {

    @GetMapping("/")
    public String home() {
        return "home";
    }

    @GetMapping("/protected")
    public String protectedPage(@AuthenticationPrincipal Saml2AuthenticatedPrincipal principal, Model model) {
        if (principal != null) {
            model.addAttribute("userName", principal.getName());
            model.addAttribute("attributes", principal.getAttributes());
            model.addAttribute("sessionIndex", principal.getSessionIndex());
            model.addAttribute("assertionId", principal.getAssertionId());
        }
        return "protected";
    }

    @GetMapping("/logout-success")
    public String logoutSuccess() {
        return "signedOut";
    }
}
